INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2834, 7, 2, "ペコリーヌとの出会い", 0, 5118061, 40, "青空の下で謁見", 1, 10118, "フリーマーケット会場", 8, 20063115, 91002, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2835, 7, 2, "マホとの出会い", 0, 5118062, 40, "未来の騎空団\nマスコット？", 1, 10118, "フリーマーケット会場", 8, 20063115, 91002, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2837, 7, 2, "アキノとの出会い", 0, 5118063, 40, "お嬢さまからの\n緊急依頼", 1, 10118, "ランドソル市街地", 8, 20063115, 91002, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (4108402, 18, 2, "ジュンとの出会い", 0, 5118064, 40, "黄金色の悩みごと", 1, 10118, "フリーマーケット会場", 8, 20063115, 91002, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (4107402, 18, 2, "カオリとの出会い", 0, 5118065, 40, "白熱！　格闘大会！", 1, 10118, "フリーマーケット会場", 8, 20063115, 91002, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (9000227, 16, 2, "ニノンとの出会い", 1, 5118066, 40, "祭り太鼓はオーエドの華", 1, 10118, "オーエド町", 8, 20063115, 91002, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2101181, 19, 3, "スズナとの出会い", 0, 5118067, 40, "人気者は遅れて\nやってくる", 1, 10118, "フリーマーケット会場", 8, 20063115, 91002, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (4109402, 18, 3, "ナナカとの出会い", 0, 5118068, 40, "巫女・ミーツ・魔法少女", 1, 10118, "ランドソル市街地", 8, 20063115, 91002, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (4305402, 18, 3, "キャル＆コッコロとの出会い", 0, 5118069, 40, "ネズ耳は二度なくなる", 1, 10118, "フリーマーケット会場", 8, 20063115, 91002, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (4101402, 18, 3, "ユカリとの出会い", 0, 5118070, 40, "この出会いにカンパイ！", 1, 10118, "ランドソル市街地", 8, 20063115, 91002, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (4106402, 18, 3, "アオイとの出会い", 0, 5118071, 40, "陰陽アンサンブル", 1, 10118, "ランドソル市街地", 8, 20063115, 91002, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2836, 7, 3, "シノブとの出会い", 1, 5118072, 40, "運試し十番勝負！", 1, 10118, "フリーマーケット会場", 8, 20063115, 91002, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (0, 0, 1, "オープニング", 0, 5118600, 0, "彼女たちの新たな日常", 0, 10118, 0, 0, 20063115, 0, 0);
